import sys
input = sys.stdin.read

def main():
    data = input().split()
    H = int(data[0])
    W = int(data[1])
    grid = data[2:H+2]

    # Convert grid to a list of lists for easier manipulation
    grid = [list(row) for row in grid]

    while True:
        marked = set()

        # Mark rows
        for i in range(H):
            row = grid[i]
            if len(set(row)) == 1:
                for j in range(W):
                    marked.add((i, j))

        # Mark columns
        for j in range(W):
            column = [grid[i][j] for i in range(H)]
            if len(set(column)) == 1:
                for i in range(H):
                    marked.add((i, j))

        if not marked:
            break

        # Remove marked cookies
        for i, j in marked:
            grid[i][j] = '.'

    # Count remaining cookies
    count = 0
    for i in range(H):
        for j in range(W):
            if grid[i][j] != '.':
                count += 1
    print(count)

if __name__ == "__main__":
    main()
